import './App.css';
import axios from 'axios'
import { BrowserRouter, Routes, Route, Link, NavLink, Navigate, useLocation } from 'react-router-dom';
import { useEffect, useState } from 'react';
import Getproducts from './components/Home';
import Signup from './components/Signup';
import Signin from './components/Signin';
import Notfound from './components/Notfound';
import 'bootstrap/dist/css/bootstrap.min.css';
import Makepayment from './components/Makepayment';
import Rooms from './components/Rooms';
import RoomDetails from './components/RoomDetails';
import Dining from './components/Dining';
import Bookings from './components/Bookings';
import Contactus from './components/Contactus';
import EventInquiry from './components/EventInquiry';
import Admin from './components/Admin';
import { isAdminAuthenticated } from './utils/adminSession';
import { fetchWorkspaceProfile } from './utils/adminCatalog';
axios.defaults.withCredentials = true;

function AdminRoute() {
  return isAdminAuthenticated() ? <Admin /> : <Navigate to="/signin" replace />;
}

function AppLayout() {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);
  const [workspace, setWorkspace] = useState(null);
  const isHomePage = location.pathname === '/';

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname, location.hash]);

  useEffect(() => {
    window.scrollTo({
      top: 0,
      left: 0,
      behavior: 'auto',
    });
  }, [location.key]);

  useEffect(() => {
    const loadWorkspace = async () => {
      try {
        const profile = await fetchWorkspaceProfile();
        setWorkspace(profile);
      } catch (error) {
        setWorkspace(null);
      }
    };

    loadWorkspace();
  }, [location.pathname]);

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--brand-primary', workspace?.primary_color || '#0d6adf');
    root.style.setProperty('--brand-accent', workspace?.accent_color || '#f0bc47');
  }, [workspace]);

  const brandName = workspace?.name || 'ELITEHOTELS';
  const brandSubtitle = workspace?.hero_title || 'Hotel & Restaurant';
  const brandMark = brandName
    .split(' ')
    .filter(Boolean)
    .slice(0, 2)
    .map((segment) => segment[0])
    .join('')
    .toUpperCase() || 'EH';

  return (
    <div className="App">
      <header className={`site-header ${isHomePage ? 'site-header--home' : ''}`}>
        <div className="site-header__inner">
          <Link to="/" className="site-brand">
            {workspace?.logo_url ? (
              <img src={workspace.logo_url} alt={brandName} className="site-brand__logo" />
            ) : (
              <span className="site-brand__mark">{brandMark}</span>
            )}
            <span className="site-brand__text">
              <strong>{brandName}</strong>
              <small>{brandSubtitle}</small>
            </span>
          </Link>

          <button
            type="button"
            className={`site-nav__toggle ${menuOpen ? 'is-open' : ''}`}
            onClick={() => setMenuOpen((open) => !open)}
            aria-label="Toggle navigation"
            aria-expanded={menuOpen}
          >
            <span></span>
            <span></span>
            <span></span>
          </button>

          <nav className={`site-nav ${menuOpen ? 'is-open' : ''}`}>
            <Link to="/rooms" className="site-nav__link">Rooms</Link>
            <Link to="/dining" className="site-nav__link">Dining</Link>
            <Link to="/bookings" className="site-nav__link">Bookings</Link>
            <Link to="/contactus" className="site-nav__link">Contact Us</Link>
            <NavLink to="/signin" className="site-nav__link">Sign In</NavLink>
            <NavLink to="/signup" className="site-nav__link">Sign Up</NavLink>
          </nav>
        </div>
      </header>

      <Routes>
        <Route path="/" element={<Getproducts />} />
        <Route path="/signin" element={<Signin />} />
        <Route path="/signup" element={<Signup />} />
        <Route path="/rooms" element={<Rooms />} />
        <Route path="/rooms/:roomSlug" element={<RoomDetails />} />
        <Route path="/dining" element={<Dining />} />
        <Route path="/bookings" element={<Bookings />} />
        <Route path="/admin" element={<AdminRoute />} />
        <Route path="/contactus" element={<Contactus />} />
        <Route path="/events" element={<EventInquiry />} />

        <Route path="/makepayment" element={<Makepayment />} />
        <Route path="*" element={<Notfound />} />
      </Routes>

      <footer className="site-footer">
        <div className="site-footer__inner">
          <div className="site-footer__brand">
            <Link to="/" className="site-brand site-footer__brand-link">
              {workspace?.logo_url ? (
                <img src={workspace.logo_url} alt={brandName} className="site-brand__logo" />
              ) : (
                <span className="site-brand__mark">{brandMark}</span>
              )}
              <span className="site-brand__text">
                <strong>{brandName}</strong>
                <small>{brandSubtitle}</small>
              </span>
            </Link>
            <p>
              {workspace?.hero_title || 'Elegant rooms, memorable dining, and warm hospitality designed to make every stay feel special.'}
            </p>
          </div>

          <div className="site-footer__links">
            <h4>Quick Links</h4>
            <Link to="/rooms">Rooms</Link>
            <Link to="/dining">Dining</Link>
            <Link to="/bookings">Bookings</Link>
            <Link to="/contactus">Contact Us</Link>
            <NavLink to="/signin">Sign In</NavLink>
            <NavLink to="/signup">Sign Up</NavLink>
          </div>

          <div className="site-footer__contact">
            <h4>Contact</h4>
            <p>{workspace?.location || 'Westlands, Nairobi'}</p>
            <p>{workspace?.contact_phone || '+254 700 123 456'}</p>
            <p>{workspace?.contact_email || 'reservations@elitehotels.com'}</p>
          </div>
        </div>

        <div className="site-footer__bottom">
          <p>&copy; 2026 {brandName}. All rights reserved.</p>
          <p>Developed by Caleb Tonny</p>
        </div>
      </footer>
    </div>
  );
}

// <BrowserRouter> comes from react-router-dom.
// It wraps the app and enables client-side routing using the browser history API.
// This allows navigation without full page reloads.

// <AppLayout> is the main layout component.
// It contains the routes and shared UI, and BrowserRouter powers the navigation.
function App() {
  return (
    <BrowserRouter>
      <AppLayout />
    </BrowserRouter>
  );
}

export default App;
